import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import './MyPetProfile.css';
import axios from 'axios';

function MyPetEditPage() {
    const { petId } = useParams();
    const navigate = useNavigate();

    const [petData, setPetData] = useState({
        name: '',
        type: '',
        profile: '',
        weight: '',
        age: '',
        size: '',
        gender: '',
        adopt: false,
    });

    const [loading, setLoading] = useState(true);

    // 🐶 반려견 정보 불러오기
    useEffect(() => {
        axios.get(`http://localhost:8080/api/pet/${petId}`, { withCredentials: true })
            .then((res) => {
                setPetData(res.data); // DTO 형태에 따라 조정
                setLoading(false);
            })
            .catch((err) => {
                console.error("반려견 정보 불러오기 실패", err);
                setLoading(false);
            });
    }, [petId]);

    // ✏️ 폼 핸들러
    const handleChange = (e) => {
        const { name, value, type, checked } = e.target;
        setPetData(prev => ({
            ...prev,
            [name]: type === 'checkbox' ? checked : value
        }));
    };

    // ✅ 제출 핸들러
    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            await axios.put(`http://localhost:8080/api/pet/edit/${petId}`, petData, {
                withCredentials: true
            });
            alert('수정 성공!');
            navigate('/mypet'); // 다시 프로필 목록으로
        } catch (err) {
            console.error('수정 실패', err);
            alert('수정 중 오류 발생');
        }
    };

    if (loading) return <p>로딩 중...</p>;

    return (
        <div className="edit-page">
            <h2>반려견 정보 수정</h2>
            <form onSubmit={handleSubmit}>
                <div className="pet-profile-info">
                    <div className="pet-info-section">
                        <h4>기본 정보</h4>
                        <div className="pet-info-grid">
                            <div className="pet-info-item">
                                <label>품종</label>
                                <span>{petProfile.type}</span>
                            </div>
                            <div className="pet-info-item">
                                <label>성별</label>
                                <span>{getGenderText(petProfile.gender)}</span>
                            </div>
                            <div className="pet-info-item">
                                <label>나이</label>
                                <span>{petProfile.age}살</span>
                            </div>
                            <div className="pet-info-item">
                                <label>몸무게</label>
                                <span>{petProfile.weight}kg</span>
                            </div>
                            <div className="pet-info-item">
                                <label>크기</label>
                                <span>{getSizeText(petProfile.size)}</span>
                            </div>
                            <div className="pet-info-item">
                                <label>입양 여부</label>
                                <span className={`adopt-badge ${petProfile.adopt ? 'adopted' : 'not-adopted'}`}>
                                    {getAdoptText(petProfile.adopt)}
                                </span>
                            </div>
                            <div className="pet-info-item">
                                <label>둥록번호</label>
                                <span>{petProfile.petId}</span>
                            </div>
                        </div>
                    </div>
                </div>

                <button type="submit">저장</button>
            </form>
        </div>
    );
}

export default MyPetEditPage;
